// Whitelist of allowed scripting operations and fields to prevent injection
const ALLOWED_SCRIPT_FUNCTIONS = [
  'Math.log', 'Math.sqrt', 'Math.abs', 'Math.pow', 'Math.max', 'Math.min',
  'Math.ceil', 'Math.floor', 'Math.round',
  'doc', 'params', '_score', 'saturation', 'sigmoid', 'randomScore',
  'decayDateLinear', 'decayDateExp', 'decayDateGauss',
  'decayGeoLinear', 'decayGeoExp', 'decayGeoGauss',
  'decayNumericLinear', 'decayNumericExp', 'decayNumericGauss'
];

const FORBIDDEN_PATTERNS = [
  /Runtime/i,
  /ProcessBuilder/i,
  /exec\s*\(/i,
  /getClass/i,
  /forName/i,
  /System\./i,
  /Thread/i,
  /Class\./i,
  /java\./i,
  /javax\./i,
  /import\s/i,
  /new\s+[A-Z]/,
  /reflect/i,
  /File/i,
  /Socket/i,
  /URL\s*\(/i,
  /Process/i,
  /getRuntime/i,
  /\\u/i,
];

function validateScript(scriptSource) {
  if (!scriptSource || typeof scriptSource !== 'string') {
    return { valid: false, reason: 'Script source must be a non-empty string' };
  }

  if (scriptSource.length > 1000) {
    return { valid: false, reason: 'Script source exceeds maximum length of 1000 characters' };
  }

  for (const pattern of FORBIDDEN_PATTERNS) {
    if (pattern.test(scriptSource)) {
      return { valid: false, reason: `Script contains forbidden pattern: ${pattern}` };
    }
  }

  return { valid: true };
}

