function buildBaseQuery(queryParams) {
  const queryType = Object.keys(queryParams)[0];
  const queryValue = queryParams[queryType];

  switch (queryType) {
    case 'match':
      return { match: queryValue };
    case 'multi_match':
      return { multi_match: queryValue };
    case 'term':
      return { term: queryValue };
    case 'terms':
      return { terms: queryValue };
    case 'range':
      return { range: queryValue };
    case 'bool':
      return { bool: queryValue };
    case 'wildcard':
      return { wildcard: queryValue };
    case 'prefix':
      return { prefix: queryValue };
    case 'exists':
      return { exists: queryValue };
    case 'nested':
      return { nested: queryValue };
    case 'geo_distance':
      return { geo_distance: queryValue };
    default:
      return { match_all: {} };
  }
}

function buildFilteredQuery(baseQuery, filters) {
  if (!filters) return baseQuery;

  const boolQuery = {
    bool: {
      must: [baseQuery],
    },
  };

  if (filters.must) {
    boolQuery.bool.must = boolQuery.bool.must.concat(filters.must);
  }
  if (filters.must_not) {
    boolQuery.bool.must_not = filters.must_not;
  }
  if (filters.should) {
    boolQuery.bool.should = filters.should;
  }
  if (filters.filter) {
    boolQuery.bool.filter = filters.filter;
  }

  return boolQuery;
}

function buildScoredQuery(filteredQuery, scoring) {
  if (!scoring || !scoring.script_source) {
    return filteredQuery;
  }

  const scriptScoreQuery = {
    script_score: {
      query: filteredQuery,
      script: {
        source: scoring.script_source,
        lang: scoring.script_lang || 'painless',
      },
    },
  };

  if (scoring.params && Object.keys(scoring.params).length > 0) {
    scriptScoreQuery.script_score.script.params = scoring.params;
  }

  if (scoring.max_boost) {
    scriptScoreQuery.script_score.max_boost = scoring.max_boost;
  }

  if (scoring.boost_mode) {
    scriptScoreQuery.script_score.boost_mode = scoring.boost_mode;
  }

  return scriptScoreQuery;
}

function buildElasticsearchBody(params) {
  const baseQuery = buildBaseQuery(params.query);
  const filteredQuery = buildFilteredQuery(baseQuery, params.filters);
  const finalQuery = buildScoredQuery(filteredQuery, params.scoring);

  const body = {
    query: finalQuery,
    from: params.pagination.from,
    size: params.pagination.size,
    track_total_hits: params.track_total_hits,
  };

  if (params.sort) {
    body.sort = params.sort;
  }

  if (params.highlight) {
    body.highlight = params.highlight;
  }

  if (params.aggregations) {
    body.aggs = params.aggregations;
  }

  if (params.source !== undefined) {
    body._source = params.source;
  }

  if (params.collapse) {
    body.collapse = params.collapse;
  }

  if (params.search_after) {
    body.search_after = params.search_after;
  }

  if (params.scoring && params.scoring.min_score !== undefined) {
    body.min_score = params.scoring.min_score;
  }

  return body;
}

