app.post('/api/search', async (req, res) => {
  try {
    // Validate input
    const { error, value: params } = searchParamsSchema.validate(req.body, {
      abortEarly: false,
      stripUnknown: true,
    });

    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map(d => ({
          message: d.message,
          path: d.path,
        })),
      });
    }

    // Validate custom scoring script if provided
    if (params.scoring && params.scoring.script_source) {
      const scriptValidation = validateScript(params.scoring.script_source);
      if (!scriptValidation.valid) {
        return res.status(400).json({
          error: 'Script validation failed',
          reason: scriptValidation.reason,
        });
      }
    }

    // Build Elasticsearch query body
    const searchBody = buildElasticsearchBody(params);

    console.log(`[${new Date().toISOString()}] Executing search on index "${params.index}":`, JSON.stringify(searchBody, null, 2));

    // Execute search
    const response = await esClient.search({
      index: params.index,
      body: searchBody,
    });

    // Format response
    const result = {
      took: response.took,
      timed_out: response.timed_out,
      total: response.hits.total,
      max_score: response.hits.max_score,
      hits: response.hits.hits.map(hit => ({
        id: hit._id,
        index: hit._index,
        score: hit._score,
        source: hit._source,
        highlight: hit.highlight || undefined,
        sort: hit.sort || undefined,
        inner_hits: hit.inner_hits || undefined,
      })),
    };

    if (response.aggregations) {
      result.aggregations = response.aggregations;
    }

    res.json(result);
  } catch (error) {
    console.error(`[${new Date().toISOString()}] Search error:`, error);

    if (error.meta && error.meta.body) {
      return res.status(error.meta.statusCode || 500).json({
        error: 'Elasticsearch error',
        details: error.meta.body.error,
      });
    }

    res.status(500).json({
      error: 'Internal server error',
      message: error.message,
    });
  }
});

// Endpoint for multi-search (batch queries)
app.post('/api/msearch', async (req, res) => {
  try {
    const { searches } = req.body;

    if (!Array.isArray(searches) || searches.length === 0) {
      return res.status(400).json({
        error: 'Validation error',
        message: '"searches" must be a non-empty array',
      });
    }

    if (searches.length > 20) {
      return res.status(400).json({
        error: 'Validation error',
        message: 'Maximum 20 searches allowed per batch',
      });
    }

    const validatedSearches = [];

    for (let i = 0; i < searches.length; i++) {
      const { error, value: params } = searchParamsSchema.validate(searches[i], {
        abortEarly: false,
        stripUnknown: true,
      });

      if (error) {
        return res.status(400).json({
          error: `Validation error in search[${i}]`,
          details: error.details.map(d => ({
            message: d.message,
            path: d.path,
          })),
        });
      }

      if (params.scoring && params.scoring.script_source) {
        const scriptValidation = validateScript(params.scoring.script_source);
        if (!scriptValidation.valid) {
          return res.status(400).json({
            error: `Script validation failed in search[${i}]`,
            reason: scriptValidation.reason,
          });
        }
      }

      validatedSearches.push(params);
    }

    // Build msearch body
    const msearchBody = [];
    for (const params of validatedSearches) {
      msearchBody.push({ index: params.index });
      msearchBody.push(buildElasticsearchBody(params));
    }

    const response = await esClient.msearch({
      body: msearchBody,
    });

    const results = response.responses.map((resp, index) => {
      if (resp.error) {
        return {
          index,
          error: resp.error,
        };
      }
      return {
        index,
        took: resp.took,
        timed_out: resp.timed_out,
        total: resp.hits.total,
        max_score: resp.hits.max_score,
        hits: resp.hits.hits.map(hit => ({
          id: hit._id,
          index: hit._index,
          score: hit._score,
          source: hit._source,
          highlight: hit.highlight || undefined,
        })),
        aggregations: resp.aggregations || undefined,
      };
    });

    res.json({ took: response.took, results });
  } catch (error) {
    console.error(`[${new Date().toISOString()}] Multi-search error:`, error);
    res.status(500).json({
      error: 'Internal server error',
      message: error.message,
    });
  }
});

