// Suggest endpoint for autocomplete
app.post('/api/suggest', async (req, res) => {
  try {
    const { index, field, text, size = 5, fuzziness = 'AUTO' } = req.body;

    if (!index || !field || !text) {
      return res.status(400).json({
        error: 'Validation error',
        message: 'index, field, and text are required',
      });
    }

    const response = await esClient.search({
      index,
      body: {
        suggest: {
          text_suggestion: {
            text,
            completion: {
              field,
              size,
              fuzzy: {
                fuzziness,
              },
            },
          },
        },
        _source: false,
      },
    });

    const suggestions = response.suggest.text_suggestion[0].options.map(option => ({
      text: option.text,
      score: option._score,
      id: option._id,
    }));

    res.json({ suggestions });
  } catch (error) {
    console.error(`[${new Date().toISOString()}] Suggest error:`, error);
    res.status(500).json({
      error: 'Internal server error',
      message: error.message,
    });
  }
});

// Explain endpoint to understand scoring
app.post('/api/explain', async (req, res) => {
  try {
    const { index, document_id, query, scoring, filters } = req.body;

    if (!index || !document_id) {
      return res.status(400).json({
        error: 'Validation error',
        message: 'index and document_id are required',
      });
    }

    const { error, value: params } = searchParamsSchema.validate(
      { index, query: query || { match: { _id: document_id } }, scoring, filters, pagination: { from: 0, size: 1 } },
      { abortEarly: false, stripUnknown: true }
    );

    if (error) {
      return res.status(400).json({
        error: 'Validation error',
        details: error.details.map(d => ({ message: d.message, path: d.path })),
      });
    }

    if (params.scoring && params.scoring.script_source) {
      const scriptValidation = validateScript(params.scoring.script_source);
      if (!scriptValidation.valid) {
        return res.status(400).json({
          error: 'Script validation failed',
          reason: scriptValidation.reason,
        });
      }
    }

    const searchBody = buildElasticsearchBody(params);

    const response = await esClient.explain({
      index,
      id: document_id,
      body: { query: searchBody.query },
    });

    res.json({
      matched: response.matched,
      explanation: response.explanation,
    });
  } catch (error) {
    console.error(`[${new Date().toISOString()}] Explain error:`, error);

    if (error.meta && error.meta.body) {
      return res.status(error.meta.statusCode || 500).json({
        error: 'Elasticsearch error',
        details: error.meta.body.error,
      });
    }

    res.status(500).json({
      error: 'Internal server error',
      message: error.message,
    });
  }
});

